import {useMarkdownEditor, MarkdownEditorView} from '@gravity-ui/markdown-editor';

function MyEditor() {
  const editor = useMarkdownEditor({initial: {markup: '# Hello'}});
  return <MarkdownEditorView stickyToolbar={true} editor={editor} />;
}

import {useMarkdownEditor, MarkdownEditorProvider, MarkdownEditorView} from '@gravity-ui/markdown-editor';

function App() {
  const editor = useMarkdownEditor({initial: {markup: ''}});
  return (
    <MarkdownEditorProvider value={editor}>
      <MarkdownEditorView stickyToolbar={true} />
    </MarkdownEditorProvider>
  );
}
